input.command:
PASS=elasticpass
kubectl -n elasticsearch exec curl-test -- curl -sk -u "elastic:${PASS}" "https://es-http.elasticsearch.svc:9200/_cluster/settings?flat_settings=true&include_defaults=true" 2>&1 | python3 -c "
import sys, json
data = json.load(sys.stdin)
# filter security-relevant defaults
for scope in ['persistent','transient','defaults']:
    vals = data.get(scope, {})
    relevant = {k:v for k,v in vals.items() if any(kw in k for kw in ['security','ssl','tls','xpack','auth','audit','action.destructive','http.cors','network','discovery','remote_cluster','anonymous'])}
    if relevant:
        print(f'--- {scope} ---')
        for k,v in sorted(relevant.items()):
            print(f'  {k}: {v}')
" 2>&1

